package k8s

import (
	"context"

	corev1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/api/resource"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/labels"
)

type PodSpec struct {
	Name      string
	Image     string
	Command   []string
	Args      []string
	Env       map[string]string
	Resources *ResourceRequirements
	Labels    map[string]string
}

type PodInfo struct {
	// Pod 名称
	Name string `json:"name"`
	// Pod 状态
	Status string `json:"status"`
	// Pod 镜像
	Image string `json:"image"`
	// Pod 创建时间
	CreatedAt string `json:"createdAt"`
	// Pod 标签
	Labels map[string]string `json:"labels"`
}

// PodManager Pod 资源管理接口
type PodManager interface {
	// CreatePod 创建 Pod
	CreatePod(ctx context.Context, pod *PodSpec) error
	// DeletePod 删除 Pod
	DeletePod(ctx context.Context, name string) error
	// GetPod 获取 Pod 信息
	GetPod(ctx context.Context, name string) (*PodInfo, error)
	// ListPods 列出 Pod
	ListPods(ctx context.Context, labels map[string]string) ([]PodInfo, error)
	// GetPodLogs 获取 Pod 日志
	GetPodLogs(ctx context.Context, name string, tailLines int64) (string, error)
}

func (c *client) CreatePod(ctx context.Context, pod *PodSpec) error {
	envVars := []corev1.EnvVar{}
	for k, v := range pod.Env {
		envVars = append(envVars, corev1.EnvVar{
			Name:  k,
			Value: v,
		})
	}

	container := corev1.Container{
		Name:    pod.Name,
		Image:   pod.Image,
		Command: pod.Command,
		Args:    pod.Args,
		Env:     envVars,
	}

	if pod.Resources != nil {
		container.Resources = corev1.ResourceRequirements{
			Requests: corev1.ResourceList{},
			Limits:   corev1.ResourceList{},
		}
		if pod.Resources.CPURequest != "" {
			container.Resources.Requests[corev1.ResourceCPU] = resource.MustParse(pod.Resources.CPURequest)
		}
		if pod.Resources.CPULimit != "" {
			container.Resources.Limits[corev1.ResourceCPU] = resource.MustParse(pod.Resources.CPULimit)
		}
		if pod.Resources.MemoryRequest != "" {
			container.Resources.Requests[corev1.ResourceMemory] = resource.MustParse(pod.Resources.MemoryRequest)
		}
		if pod.Resources.MemoryLimit != "" {
			container.Resources.Limits[corev1.ResourceMemory] = resource.MustParse(pod.Resources.MemoryLimit)
		}
	}

	k8sPod := &corev1.Pod{
		ObjectMeta: metav1.ObjectMeta{
			Name:   pod.Name,
			Labels: pod.Labels,
		},
		Spec: corev1.PodSpec{
			Containers: []corev1.Container{container},
		},
	}

	_, err := c.clientset.CoreV1().Pods(c.namespace).Create(ctx, k8sPod, metav1.CreateOptions{})
	return err
}

func (c *client) DeletePod(ctx context.Context, name string) error {
	return c.clientset.CoreV1().Pods(c.namespace).Delete(ctx, name, metav1.DeleteOptions{})
}

func (c *client) GetPod(ctx context.Context, name string) (*PodInfo, error) {
	pod, err := c.clientset.CoreV1().Pods(c.namespace).Get(ctx, name, metav1.GetOptions{})
	if err != nil {
		return nil, err
	}

	image := ""
	if len(pod.Spec.Containers) > 0 {
		image = pod.Spec.Containers[0].Image
	}

	return &PodInfo{
		Name:      pod.Name,
		Status:    string(pod.Status.Phase),
		Image:     image,
		CreatedAt: pod.CreationTimestamp.Format("2006-01-02 15:04:05"),
		Labels:    pod.Labels,
	}, nil
}

func (c *client) ListPods(ctx context.Context, labelMap map[string]string) ([]PodInfo, error) {
	selector := labels.SelectorFromSet(labelMap)
	pods, err := c.clientset.CoreV1().Pods(c.namespace).List(ctx, metav1.ListOptions{
		LabelSelector: selector.String(),
	})
	if err != nil {
		return nil, err
	}

	var podInfos []PodInfo
	for _, pod := range pods.Items {
		image := ""
		if len(pod.Spec.Containers) > 0 {
			image = pod.Spec.Containers[0].Image
		}

		podInfos = append(podInfos, PodInfo{
			Name:      pod.Name,
			Status:    string(pod.Status.Phase),
			Image:     image,
			CreatedAt: pod.CreationTimestamp.Format("2006-01-02 15:04:05"),
			Labels:    pod.Labels,
		})
	}

	return podInfos, nil
}

func (c *client) GetPodLogs(ctx context.Context, name string, tailLines int64) (string, error) {
	req := c.clientset.CoreV1().Pods(c.namespace).GetLogs(name, &corev1.PodLogOptions{
		TailLines: &tailLines,
	})

	logs, err := req.Stream(ctx)
	if err != nil {
		return "", err
	}
	defer logs.Close()

	var logData []byte
	buf := make([]byte, 1024)
	for {
		n, err := logs.Read(buf)
		if n > 0 {
			logData = append(logData, buf[:n]...)
		}
		if err != nil {
			break
		}
	}

	return string(logData), nil
}

		return
	}

	commonmodel.RespondSuccess(c, nil)
}

// GetDevmachineStatus 获取 Devmachine 状态
// @Summary      获取 Devmachine 状态
// @Description  获取指定 namespace 中 Devmachine 的状态信息
// @Tags         开发机管理
// @Produce      json
// @Security     BearerAuth
// @Param        namespace path string true "Namespace"
// @Param        name path string true "Devmachine 名称"
// @Success      200  {object}  devmachinemodel.Devmachine
// @Failure      400  {object}  map[string]string
// @Failure      500  {object}  map[string]string
// @Router       /devmachine/{namespace}/{name}/status [get]
func (h *Handler) GetDevmachineStatus(c *gin.Context) {
	namespace := c.Param("namespace")
	name := c.Param("name")

	status, err := h.service.GetDevmachineStatus(c.Request.Context(), namespace, name)
	if err != nil {
		h.logger.Error("failed to get devmachine status", zap.Error(err), zap.String("namespace", namespace), zap.String("name", name))
		commonmodel.RespondInternalError(c, err.Error())
		return
	}

	commonmodel.RespondSuccess(c, status)
}

