func (c *client) CreateDeployment(ctx context.Context, deployment *appsv1.Deployment) error {
	_, err := c.clientset.AppsV1().Deployments(deployment.Namespace).Create(ctx, deployment, metav1.CreateOptions{})
	return err
}

func (c *client) UpdateDeployment(ctx context.Context, deployment *appsv1.Deployment) error {
	oldDeployment, err := c.clientset.AppsV1().Deployments(deployment.Namespace).Get(ctx, deployment.Name, metav1.GetOptions{})
	if err != nil {
		return err
	}
	deployment.ResourceVersion = oldDeployment.ResourceVersion
	_, err = c.clientset.AppsV1().Deployments(deployment.Namespace).Update(ctx, deployment, metav1.UpdateOptions{})
	return err
}

func (c *client) DeleteDeployment(ctx context.Context, namespace, name string) error {
	return c.clientset.AppsV1().Deployments(namespace).Delete(ctx, name, metav1.DeleteOptions{})
}

func (c *client) GetDeployment(ctx context.Context, namespace, name string) (*appsv1.Deployment, error) {
	return c.clientset.AppsV1().Deployments(namespace).Get(ctx, name, metav1.GetOptions{})
}

func (c *client) ListDeployments(ctx context.Context) ([]*appsv1.Deployment, error) {
	deploymentsList, err := c.clientset.AppsV1().Deployments(c.namespace).List(ctx, metav1.ListOptions{})
	if err != nil {
		return nil, err
	}

	var deployments []*appsv1.Deployment
	for i := range deploymentsList.Items {
		deployments = append(deployments, &deploymentsList.Items[i])
	}
	return deployments, nil
}

