	return ""
}

// GetPodNameFromDeployment 从Deployment获取Pod名称
func GetPodNameFromDeployment(deployment *appsv1.Deployment) string {
	if len(deployment.Spec.Template.Spec.Containers) > 0 {
		// 实际的Pod名称由Deployment控制器生成，包含随机后缀
		// 这里返回Deployment名称作为参考
		return deployment.Name
	}
	return ""
}

// IsDevmachineRunning 检查开发机是否正在运行
func IsDevmachineRunning(deployment *appsv1.Deployment) bool {
	return deployment.Status.ReadyReplicas > 0
}

// GetContainerImage 获取容器镜像
func GetContainerImage(deployment *appsv1.Deployment) string {
	if len(deployment.Spec.Template.Spec.Containers) > 0 {
		return deployment.Spec.Template.Spec.Containers[0].Image
	}
	return ""
}

// GetEnvironmentVars 获取环境变量
func GetEnvironmentVars(deployment *appsv1.Deployment) map[string]string {
	envVars := make(map[string]string)
	if len(deployment.Spec.Template.Spec.Containers) > 0 {
		container := deployment.Spec.Template.Spec.Containers[0]
		for _, env := range container.Env {
			envVars[env.Name] = env.Value
		}
	}
	return envVars
}

// GetAnnotations 获取注解
func GetAnnotations(deployment *appsv1.Deployment) map[string]string {
	if deployment.Annotations != nil {
		return deployment.Annotations
	}
	return make(map[string]string)
}

// GetLabels 获取标签
func GetLabels(deployment *appsv1.Deployment) map[string]string {
	if deployment.Labels != nil {
		return deployment.Labels
	}
	return make(map[string]string)
}

// HasSpecificAnnotation 检查是否有特定注解
func HasSpecificAnnotation(deployment *appsv1.Deployment, key, value string) bool {
	annotations := GetAnnotations(deployment)
	return annotations[key] == value
}

// HasSpecificLabel 检查是否有特定标签
func HasSpecificLabel(deployment *appsv1.Deployment, key, value string) bool {
	labels := GetLabels(deployment)
	return labels[key] == value
}

// GetQueueName 从Deployment获取队列名称
func GetQueueName(deployment *appsv1.Deployment) string {
	annotations := GetAnnotations(deployment)
	return annotations[volcanoQueueName]
}

