// NewClient 创建 K8s 客户端
func NewClient(cfg *config.Config) (Client, error) {
	var k8sConfig *rest.Config
	var err error

	if cfg.K8s.Kubeconfig != "" {
		configPath := cfg.K8s.Kubeconfig
		if !filepath.IsAbs(configPath) {
			configPath = filepath.Join(filepath.Dir(""), configPath)
		}
		k8sConfig, err = clientcmd.BuildConfigFromFlags("", configPath)
	} else {
		k8sConfig, err = rest.InClusterConfig()
	}

	if err != nil {
		return nil, fmt.Errorf("failed to build k8s config: %w", err)
	}

	clientset, err := kubernetes.NewForConfig(k8sConfig)
	if err != nil {
		return nil, fmt.Errorf("failed to create k8s clientset: %w", err)
	}

	volcanoClient, err := volcanoclient.NewForConfig(k8sConfig)
	if err != nil {
		return nil, fmt.Errorf("failed to create volcano clientset: %w", err)
	}

	namespace := cfg.K8s.Namespace
	if namespace == "" {
		namespace = "default"
	}

	// 从配置中提取允许的GPU类型
	allowedGPUTypes := make([]string, len(cfg.Resources.GPUTypes))
	for i, gpuType := range cfg.Resources.GPUTypes {
		allowedGPUTypes[i] = gpuType.Name
	}

	return &client{
		clientset:       clientset,
		volcanoClient:   volcanoClient,
		namespace:       namespace,
		allowedGPUTypes: allowedGPUTypes,
	}, nil
}

