package devmachine

import "code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/pkg/util"

// Constants for dev machine status
const (
	StatusCreating         = "creating"         // 创建中
	StatusPending          = "pending"          // 排队中
	StatusTerminating      = "terminating"      // 关机中
	StatusCrashLoopBackOff = "crashloopbackoff" // 开机失败
	StatusRunning          = "running"          // 运行中
	StatusStopped          = "stopped"          // 已关机
	StatusError            = "error"            // 错误状态
	StatusUnknown          = "unknown"          // 未知状态
)

type StatusEnumProvider struct{}

var EnumItemMap = map[string]string{
	StatusCreating:         "创建中",
	StatusPending:          "排队中",
	StatusTerminating:      "关机中",
	StatusCrashLoopBackOff: "开机失败",
	StatusRunning:          "运行中",
	StatusStopped:          "已关机",
	StatusError:            "错误状态",
	StatusUnknown:          "未知状态",
}

func (p *StatusEnumProvider) GetEnum() []util.EnumItem {
	// 定义固定的顺序
	orderedKeys := []string{
		StatusCreating,
		StatusPending,
		StatusTerminating,
		StatusCrashLoopBackOff,
		StatusRunning,
		StatusStopped,
		StatusError,
		StatusUnknown,
	}
	enumItems := make([]util.EnumItem, 0, len(orderedKeys))
	for _, key := range orderedKeys {
		if value, exists := EnumItemMap[key]; exists {
			enumItems = append(enumItems, util.EnumItem{
				Key:   key,
				Value: value,
			})
		}
	}
	return enumItems
}

