type GetDevmachineStatusResponse struct {
	Namespace string `json:"namespace"`
	Name      string `json:"name"`
	// Phase 当前所处的生命周期阶段：
	// scheduling（等待调度）→ pulling_image（拉取镜像）→ initializing（Init容器）→ starting（业务容器启动）→ running（运行中）
	// 异常阶段：failed（失败）/ terminating（关机中）/ stopped（已停止）/ unknown（未知）
	Phase   string `json:"phase"`
