	StatusCreating         = "creating"         // 创建中
	StatusPending          = "pending"          // 排队中
	StatusTerminating      = "terminating"      // 关机中
	StatusCrashLoopBackOff = "crashloopbackoff" // 开机失败
	StatusRunning          = "running"          // 运行中
	StatusStopped          = "stopped"          // 已关机
	StatusError            = "error"            // 错误状态
	StatusUnknown          = "unknown"          // 未知状态
)

// Pod 生命周期阶段常量（细粒度，用于状态详情查询）
// 生命周期顺序：scheduling → pulling_image → initializing → starting → running
const (
	PhaseScheduling   = "scheduling"    // Pod 等待调度（未分配节点）
	PhasePullingImage = "pulling_image" // 拉取镜像中（已调度，容器尚未创建）
	PhaseInitializing = "initializing"  // Init 容器运行中
	PhaseStarting     = "starting"      // 业务容器启动中（ContainerCreating 或 Running 但未 Ready）
	PhaseRunning      = "running"       // 运行中（所有容器 Ready）
	PhaseStopped      = "stopped"       // 已停止（副本数为 0）
	PhaseTerminating  = "terminating"   // 关机中（DeletionTimestamp 已设置）
	PhaseFailed       = "failed"        // 失败（ImagePullBackOff / CrashLoopBackOff / OOMKilled 等）
	PhaseUnknown      = "unknown"       // 未知
)

type StatusEnumProvider struct{}

var EnumItemMap = map[string]string{
	StatusCreating:         "创建中",
	StatusPending:          "排队中",
	StatusTerminating:      "关机中",
	StatusCrashLoopBackOff: "开机失败",
	StatusRunning:          "运行中",
	StatusStopped:          "已关机",
	StatusError:            "错误状态",
	StatusUnknown:          "未知状态",
}

func (p *StatusEnumProvider) GetEnum() []util.EnumItem {
	// 定义固定的顺序
	orderedKeys := []string{
		StatusCreating,
		StatusPending,
		StatusTerminating,
		StatusCrashLoopBackOff,
		StatusRunning,
		StatusStopped,
		StatusError,
		StatusUnknown,
	}
	enumItems := make([]util.EnumItem, 0, len(orderedKeys))
	for _, key := range orderedKeys {
		if value, exists := EnumItemMap[key]; exists {
			enumItems = append(enumItems, util.EnumItem{
				Key:   key,
				Value: value,
			})
		}
	}
	return enumItems
}

