468	func getPhaseFromPod(pod *corev1.Pod) (phase, reason, message string, ready bool) {
469		// Pod 正在被删除
470		if pod.DeletionTimestamp != nil {
471			return devmachinemodel.PhaseTerminating, "", "开发机正在关闭", false
472		}
473	
474		switch pod.Status.Phase {
475		case corev1.PodPending:
476			return getPendingPhaseDetail(pod)
477		case corev1.PodRunning:
478			return getRunningPhaseDetail(pod)
479		case corev1.PodFailed:
480			return devmachinemodel.PhaseFailed, pod.Status.Reason, pod.Status.Message, false
481		case corev1.PodSucceeded:
482			return devmachinemodel.PhaseStopped, "", "容器已正常退出", false
